/**
 * Conversor de tabelas Markdown -> tópicos para WhatsApp
 * - Não truncar o primeiro item (só pula header quando há separador '---' real)
 * - Ignora blocos de código (``` ... ```)
 * - Mantém linhas fora de tabela intactas
 * - Remove asteriscos do nome e aceita 2ª/3ª coluna como valor/percentual
 * - Uso típico em n8n (Function): processa item.json.output
 */

function converterTabelaParaTopicos(texto) {
  const linhas = texto.split('\n');
  let textoConvertido = '';
  let dentroDeTabela = false;
  let cabecalhoProcessado = false;
  let emCodigo = false;

  const ehSeparadorHeader = (l) =>
    /^\s*\|?\s*:?-{3,}\s*(\|\s*:?-{3,}\s*)+\|?\s*$/.test(l);

  for (let i = 0; i < linhas.length; i++) {
    const linhaBruta = linhas[i];
    const linha = linhaBruta.trim();

    // 1) Não mexer em blocos de código
    if (linha.startsWith('```')) {
      emCodigo = !emCodigo;
      textoConvertido += linhaBruta + '\n';
      // Ao entrar/sair de código, considere que qualquer tabela anterior acabou
      if (dentroDeTabela) {
        textoConvertido += '\n';
        dentroDeTabela = false;
        cabecalhoProcessado = false;
      }
      continue;
    }
    if (emCodigo) {
      textoConvertido += linhaBruta + '\n';
      continue;
    }

    // 2) Heurística simples: linha com '|' e ao menos 3 segmentos = possível tabela
    const ehLinhaComPipes = linha.includes('|') && linha.split('|').length > 2;

    if (ehLinhaComPipes) {
      // 2.1) Linha separadora de header? apenas marque que estamos na tabela e pule
      if (ehSeparadorHeader(linha)) {
        dentroDeTabela = true;
        continue;
      }

      // 2.2) Parse das colunas
      const colunas = linha
        .split('|')
        .map(col => col.trim())
        .filter(col => col !== '');

      if (colunas.length >= 2) {
        dentroDeTabela = true;

        // 2.3) Só pular a 1ª linha se a próxima for separador => existe header
        if (!cabecalhoProcessado) {
          const proxima = (i + 1 < linhas.length) ? linhas[i + 1].trim() : '';
          const proxEhSeparador = ehSeparadorHeader(proxima);
          cabecalhoProcessado = true;

          if (proxEhSeparador) {
            // pula header (linha atual) e o separador (próxima linha)
            i++; 
            continue;
          }
          // Sem header: trata esta linha como dado (não dá continue)
        }

        // 2.4) Montagem do tópico
        const item = colunas[0].replace(/\*/g, ''); // remove asteriscos do nome
        const valor = colunas[1];
        const percentual = colunas.length > 2 ? colunas[2] : '';

        textoConvertido += `• ${item}: ${valor}${percentual ? ` (${percentual})` : ''}\n`;
      }
    } else {
      // 3) Linha normal (fora de tabela)
      if (dentroDeTabela) {
        // encerra bloco de tabela com linha em branco
        textoConvertido += '\n';
        dentroDeTabela = false;
        cabecalhoProcessado = false;
      }
      textoConvertido += linhaBruta + '\n';
    }
  }

  // 4) Se terminou dentro de tabela, fecha com quebra de linha
  if (dentroDeTabela) {
    textoConvertido += '\n';
  }

  return textoConvertido.trim();
}

// ===== n8n: processa todos os itens de entrada =====
const inputData = $input.all();

