  workspace.datasets?.forEach(dataset => {
    // Filtrar apenas datasets que contêm "ia_" no nome
    if (dataset.name && dataset.name.toLowerCase().includes('ia_')) {

      // Percorrer todas as tabelas do dataset
      dataset.tables?.forEach(table => {

        // PULAR tabelas ocultas
        if (table.isHidden) {
          return; // Skip esta tabela
        }

        // Filtrar apenas colunas visíveis
        const visibleColumns = table.columns ? table.columns.filter(column => !column.isHidden) : [];

        // Se não tem colunas visíveis, pular esta tabela
        if (visibleColumns.length === 0) {
          return; // Skip esta tabela
        }

        // Adicionar nome da tabela com formatação markdown
        output += `## ${table.name}\n\n`;

        // Adicionar colunas visíveis em lista markdown
        const columnNames = visibleColumns.map(column => `- ${column.name}`);
        output += columnNames.join('\n') + '\n\n';
      });
    }
  });
});

// Retornar como um único texto
return [
