];

// Node CODE - Extrair apenas Medidas Visíveis e suas Descrições

const inputData = $input.all()[0].json;
const workspaces = inputData.workspaces;

let output = "# Medidas e Descrições do Dataset\n\n";

// Percorrer todos os workspaces
workspaces.forEach(workspace => {
  // Percorrer todos os datasets
  workspace.datasets?.forEach(dataset => {
    // Filtrar apenas datasets que contêm "ia_" no nome
    if (dataset.name && dataset.name.toLowerCase().includes('ia_')) {

      // Percorrer todas as tabelas do dataset
      dataset.tables?.forEach(table => {

        // Verificar se a tabela tem medidas
        if (table.measures && table.measures.length > 0) {

          // Filtrar apenas medidas visíveis
          const visibleMeasures = table.measures.filter(measure => !measure.isHidden);

          // Se tem medidas visíveis, processar
          if (visibleMeasures.length > 0) {

            // Adicionar nome da tabela como cabeçalho markdown
            output += `## ${table.name}\n\n`;

            // Adicionar cada medida visível em lista markdown
            visibleMeasures.forEach(measure => {
              output += `- **${measure.name}**`;

              // Adicionar descrição se existir
              if (measure.description && measure.description.trim() !== '') {
                output += ` - ${measure.description}`;
              }

              output += '\n';
            });

            output += '\n'; // Linha em branco entre tabelas
          }
        }
      });
    }
  });
});

// Se não encontrou medidas, avisar
if (output === "# Medidas\n\n") {
  output += "**Nenhuma medida visível encontrada.**";
}

// Retornar como um único texto
return [
  {
    json: {
      texto: output.trim()
    }
  }
];

