  text = text
    .replace(/\\/g, '\\\\')  // barras invertidas
    .replace(/"/g, '\\"');   // aspas duplas

  // 4) Garante que qualquer quebra de linha literal vira \n
  text = text.replace(/\r\n/g, '\\n').replace(/\r/g, '\\n').replace(/\n/g, '\\n');

