// Nó Function ou Code no n8n
const hoje = new Date();

// Criar formatador para Brasília
const formatador = new Intl.DateTimeFormat('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  year: 'numeric',
  month: 'numeric',
  day: 'numeric'
});

// Obter partes da data
const partes = formatador.formatToParts(hoje);
const dia = parseInt(partes.find(p => p.type === 'day').value);
const mes = parseInt(partes.find(p => p.type === 'month').value);
const ano = parseInt(partes.find(p => p.type === 'year').value);

// Formatar como DATE do DAX
const dataHoje = `DATE(${ano}, ${mes}, ${dia})`;

return {
  dataHoje: dataHoje,
  ano: ano,
  mes: mes,
  dia: dia,
  dataFormatadaBR: formatador.format(hoje)
};

